ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
	"correlationId": (correlationId default uuid()),
	"statusCode": vars.httpStatus,
	"statusMessage": "PO was created succesfully",
	"description": "Sucessfully creared P21 PO. – reference P21 Purchase Order Number : " ++ (payload.Order.OrderNo default "NA"),
	"timestamp": (((now() >> "UTC")  as String {
		format : "yyyy/MM/dd HH:mm:ss"
	}) ++ " UTC"),
	notificationRequired: true
}

ee:message.ee:set-payload:
%dw 2.0 import * from dw::core::Strings output text/plain
fun safe(v, d="N/A") = if (v == null or (v is String and trim(v) == "")) d else v
var successResp = vars.successResponse default {} var sysInfo = vars.systemInformation default {} var integration = vars.integration default vars.initialVariables default {}
var cdm = (vars.initialPayload default [])[0].b2bMessage default {} var cdmHeader = cdm.header default {}
var sourceSystem = if (upper(sysInfo.source default "") == "COUPA") "ADM Coupa" else safe(sysInfo.source, "P21")
var targetSystem = safe(sysInfo.target, "P21")
var flowDirection = if (lower(sourceSystem) == "apm") "INBOUND" else if ((lower(sourceSystem) contains "coupa") and lower(targetSystem) == "p21") "INBOUND" else "OUTBOUND"
var msgPoNumber = safe(cdmHeader.poNumber default "" as String, safe(vars.initialPayload[0].b2bMessage.header.poNumber default "" as String, safe(vars.initialPayload.Order.PoNo default "" as String, "N/A") ))
var senderKey = safe(cdmHeader.senderId, safe(sysInfo.source, "N/A")) as String
var msgVendorId = if (p('partner.inbound.' ++ senderKey) != null) p('partner.inbound.' ++ senderKey) else if (p('partner.outbound.' ++ senderKey) != null) p('partner.outbound.' ++ senderKey) else "N/A"
var companyName = safe(vars.purchaseOrderData.value.company_no[0] default "" as String, safe(if(lower(sourceSystem) contains "coupa") "King Filtration" else "", "N/A"))
// Extract P21 Order Number from successResponse description or payload var p21OrderNumber = payload.Order.OrderNo default vars.initialPayload.Order.OrderNo default "N/A"
var data = { flowDirection: flowDirection, documentType: safe(sysInfo."integration-type", safe(cdmHeader.documentType, "API")), appName: p('api.name') default "Mule Application", transactionType: safe(sysInfo."integration-type", safe(cdmHeader.documentType, "API")), environment: sysInfo.env default upper(p('mule.env')), route: sourceSystem ++ " → Mule → " ++ targetSystem, successTitle: "Transaction Processed Successfully", bannerColor: "#10b981", status: "SUCCESS", statusCode: successResp.statusCode default vars.httpStatus default 200, statusMessage: successResp.statusMessage default "PO was created successfully", message: successResp.description default ("Purchase Order " ++ msgPoNumber ++ " (Vendor: " ++ msgVendorId ++ ") has been successfully processed" ++ " on the " ++ sourceSystem ++ " → " ++ targetSystem ++ " route." ++ (if (p21OrderNumber != "N/A") " P21 Order Number: " ++ p21OrderNumber else "")), vendorName: msgVendorId, businessKey: "PO " ++ msgPoNumber, p21OrderNumber: p21OrderNumber, transmissionId: vars.initialPayload[0].b2bMessage.header.transmissionId default vars.initialPayload.Order.TransmissionId default "N/A", companyName: companyName, keyLabel: "Correlation ID", key: successResp.correlationId default correlationId default uuid(), timestamp: successResp.timestamp default (now() as String {format: "yyyy-MM-dd HH:mm:ss"}) }
var template = readUrl("classpath://templates/success-template.html", "text/plain") --- template replace /\$\{(\w+)\}/ with ((m) -> (data[m[1]] as String) default "" )

ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
	"correlationId": (correlationId default uuid()),
	"statusCode": vars.httpStatus,
	"statusMessage": "CUSTOM:VALIDATION_FAILED",
	"description": "Item IDs missing in Coupa request; proceeded with P21 PO creation – reference P21 Order Number : " ++ (payload.Order.OrderNo default "NA"),
	"timestamp": (((now() >> "UTC")  as String {
		format : "yyyy/MM/dd HH:mm:ss"
	}) ++ " UTC"),
	notificationRequired: true
}
